#!/usr/bin/env node
// Generated by Keel — modern-web-guidance PostToolUse reminder hook.
// Fires after any frontend file edit and reminds to check modern web platform patterns.
// No dependencies beyond Node.js built-ins.
import { readFileSync } from 'fs'

let raw = ''
try { raw = readFileSync('/dev/stdin', 'utf8') } catch { process.exit(0) }
let input
try { input = JSON.parse(raw) } catch { process.exit(0) }

const filePath = input?.tool_input?.file_path || ''
const FE_EXTS = /\.(html|css|js|mjs|ts|tsx|jsx|vue|svelte|astro|scss|sass|less)$/i

if (FE_EXTS.test(filePath)) {
  const filename = filePath.split('/').pop()
  process.stdout.write(
    '[modern-web-guidance] Frontend file touched: ' + filename + '\n' +
    'Before adding new UI patterns, check for current platform guidance:\n' +
    '  npx -y modern-web-guidance@latest search "<what you want to do>"\n' +
    'Prefer native: <dialog> for modals, popover API for popovers, CSS scroll-driven animations, View Transitions API.\n'
  )
}
process.exit(0)
